    ],\n            [\n              104.18758,\n              15.651894\n            ],\n            [\n              104.189167,\n              15.66232\n            ],\n            [\n              104.177154,\n              15.66096\n            ],\n            [\n              104.177381,\n              15.668439\n            ],\n            [\n              104.147237,\n              15.700397\n            ],\n            [\n              104.15041,\n              15.710143\n            ],\n            [\n              104.141571,\n              15.709236\n            ],\n            [\n              104.130692,\n              15.692691\n            ],\n            [\n              104.121172,\n              15.69881\n            ],\n            [\n              104.131825,\n              15.70289\n            ],\n            [\n              104.131145,\n              15.721248\n            ],\n            [\n              104.143157,\n              15.726235\n            ],\n            [\n              104.135225,\n              15.738247\n            ],\n            [\n              104.144064,\n              15.747766\n            ],\n            [\n              104.134545,\n              15.751846\n            ],\n            [\n              104.129785,\n              15.765671\n            ],\n            [\n              104.141344,\n              15.780177\n            ],\n            [\n              104.136584,\n              15.796269\n            ],\n            [\n              104.11256,\n              15.805562\n            ],\n            [\n              104.097148,\n              15.82256\n            ],\n            [\n              104.075843,\n              15.835479\n            ],\n            [\n              104.06995,\n              15.826413\n            ],\n            [\n              104.080602,\n              15.81984\n            ],\n            [\n              104.076976,\n              15.813948\n            ],\n            [\n              104.041165,\n              15.794002\n            ],\n            [\n              104.003995,\n              15.792643\n            ],\n            [\n              104.001502,\n              15.809868\n            ],\n            [\n              104.013968,\n              15.814854\n            ],\n            [\n              104.011021,\n              15.826866\n            ],\n            [\n              104.018954,\n              15.828453\n            ],\n            [\n              104.014421,\n              15.838879\n            ],\n            [\n              104.021447,\n              15.835932\n            ],\n            [\n              104.02938,\n              15.849078\n            ],\n            [\n              104.03074,\n              15.857237\n            ],\n            [\n              104.022127,\n              15.86381\n            ],\n            [\n              104.038446,\n              15.866077\n            ],\n            [\n              104.02734,\n              15.867437\n            ],\n            [\n              104.034139,\n              15.872196\n            ],\n            [\n              104.019407,\n              15.882849\n            ],\n            [\n              104.022807,\n              15.888062\n            ],\n            [\n              104.018047,\n              15.891008\n            ],\n            [\n              104.017821,\n              15.908007\n            ],\n            [\n              104.026887,\n              15.910273\n            ],\n            [\n              104.039352,\n              15.937924\n            ],\n            [\n              104.029606,\n              15.956509\n            ],\n            [\n              104.02054,\n              15.94835\n            ],\n            [\n              104.016234,\n              15.955376\n            ],\n            [\n              104.02326,\n              15.973055\n            ],\n            [\n              104.033459,\n              15.980761\n            ],\n            [\n              104.06315,\n              15.982801\n            ],\n            [\n              104.099414,\n              15.972828\n            ],\n            [\n              104.108707,\n              15.984614\n            ],\n            [\n              104.106214,\n              16.002746\n            ],\n            [\n              104.113693,\n              16.010452\n            ],\n            [\n              104.119359,\n              16.031983\n            ],\n            [\n              104.107573,\n              16.045356\n            ],\n            [\n              104.101907,\n              16.07414\n            ],\n            [\n              104.119359,\n              16.110857\n            ],\n            [\n              104.142704,\n              16.105871\n            ],\n            [\n              104.157436,\n              16.116523\n            ],\n            [\n              104.177608,\n              16.143494\n            ],\n            [\n              104.197779,\n              16.144401\n            ],\n            [\n              104.209339,\n              16.160266\n            ],\n            [\n              104.219084,\n              16.15256\n            ],\n            [\n              104.232003,\n              16.162533\n            ],\n            [\n              104.251042,\n              16.190864\n            ],\n            [\n              104.258068,\n              16.217382\n            ],\n            [\n              104.295692,\n              16.230074\n            ],\n            [\n              104.31881,\n              16.247299\n            ],\n            [\n              104.324249,\n              16.263391\n            ],\n            [\n              104.343514,\n              16.286509\n            ],\n            [\n              104.345781,\n              16.306455\n            ],\n            [\n              104.35462,\n              16.318467\n            ],\n            [\n              104.362553,\n              16.332972\n            ],\n            [\n              104.374565,\n              16.341358\n            ],\n            [\n              104.407203,\n              16.344078\n            ]\n          ]\n        ]\n      }\n    }\n  ]\n}"; 
        const geojson_object = JSON.parse(geojson_data_string); 
        
        var geojson;
        var incomeChartInstance = null; 
        var totalAmount = 0; 

        // ----------------------------------------------------
        // 1. Leaflet Map Style Functions (Colors updated for blue theme)
        // ----------------------------------------------------
        function getColor(amount) {
            return amount > 1000000 ? '#0B3D91' :  // deep sapphire
                amount > 500000  ? '#155EAD' :  // medium steel blue
                amount > 100000  ? '#2B7FC1' :  // bright blue
                amount > 50000   ? '#4FA3D1' :  // sky blue
                amount > 10000   ? '#78C0E0' :  // soft blue
                amount > 5000    ? '#A3D4ED' :  // light blue
                amount > 1000    ? '#D0E9F7' :  // pale blue
                                    '#F2FAFF';   // almost white
        }



        function style(feature) {
            return {
                fillColor: getColor(feature.properties.ForeignerAmount),
                weight: 1.5,
                opacity: 1,
                color: 'white',
                dashArray: '3',
                fillOpacity: 0.7
            };
        }

        function findProvinceData(provinceName) {
            const feature = geojson_object.features.find(f => f.properties.name === provinceName);
            return feature ? feature.properties : null;
        }

        // ----------------------------------------------------
        // 2. Map Interaction Logic (Unchanged)
        // ----------------------------------------------------

        /**
         * Only highlights the feature and updates the info panel on mouseover.
         * DOES NOT update the chart.
         */
        function highlightFeature(e) {
            var layer = e.target;
            
            // Reset ALL previous highlights
            if (geojson) {
                geojson.eachLayer(function(l) {
                    geojson.resetStyle(l);
                });
            }
            
            // Apply highlight style
            layer.setStyle({ weight: 4, color: '#0056b3', dashArray: '', fillOpacity: 0.8 }); // Blue highlight
            if (!L.Browser.ie && !L.Browser.opera && !L.Browser.edge) { layer.bringToFront(); }
            
            // Update info panel on hover
            info.update(layer.feature.properties);
        }

        /**
         * Resets the map highlight on mouseout, UNLESS the province is currently selected.
         * DOES NOT update the chart.
         */
        function resetHighlight(e) {
            const selectedProvince = document.getElementById('province-select').value;
            if (e.target.feature.properties.name === selectedProvince) {
                // Keep the style if it is the currently selected province
                return;
            }

            geojson.resetStyle(e.target);
            info.update(); // Reset info panel content
        }

        /**
         * Handles map click: updates the dropdown, which in turn triggers the main update logic.
         */
        function clickFeature(e) {
            const selectedName = e.target.feature.properties.name;
            const selectElement = document.getElementById('province-select');
            
            // Zoom to the bounds immediately
            map.fitBounds(e.target.getBounds());

            // Check if the selection actually changed
            if (selectElement.value !== selectedName) {
                selectElement.value = selectedName;
                
                // Manually fire the change event to trigger the main selectElement.onchange handler
                selectElement.dispatchEvent(new Event('change'));
            }
            
            // Ensure the clicked feature is highlighted immediately
              highlightFeature(e);
        }

        function onEachFeature(feature, layer) {
            feature.properties.layer = layer; 
            layer.on({
                mouseover: highlightFeature,
                mouseout: resetHighlight,
                click: clickFeature 
            });
        }
        
        // --- Map Initialization ---

        var map = L.map('mapid').setView([13.736717, 100.523186], 6);

        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            maxZoom: 19,
            attribution: '© OpenStreetMap contributors'
        }).addTo(map);

        var info = L.control();

        info.onAdd = function (map) {
            this._div = L.DomUtil.create('div', 'info');
            this.update();
            return this._div;
        };
        
        info.update = function (props) {
            // Icon color updated to blue for consistency
            const amount_icon_html = '<span style="color: #0056b3; font-size: 1.2em;">👤</span>';
            const income_icon      = '💰';
            const room_icon_html   = '<span style="color: #0056b3; font-size: 1.2em;">🏨</span>'; 

            this._div.innerHTML = '<h4>Foreigner Tourist</h4>' + (props ?
                '<b>' + props.name + '</b><br />' +
                amount_icon_html + ' Visits: ' +
                (props.ForeignerAmount !== null ? props.ForeignerAmount.toLocaleString() : 'N/A') + '<br />' +
                income_icon + ' Income: ' +
                (props.ForeignerIncome !== null ? props.ForeignerIncome.toLocaleString() + ' M THB' : 'N/A') + '<br />' +
                room_icon_html + ' Avg. Room Rate: ' +
                (props.RoomRate !== null ?  + props.RoomRate.toLocaleString() : ' N/A') 
                : 'Hover over a province to see data');
        };

        info.addTo(map);

        geojson = L.geoJson(geojson_object, { 
            style: style,
            onEachFeature: onEachFeature
        }).addTo(map);

        var legend = L.control({position: 'bottomright'});

        legend.onAdd = function (map) {
            var div = L.DomUtil.create('div', 'info legend'),
                // Legend grades match the getColor function
                grades = [0, 1000, 5000, 10000, 50000, 100000, 500000, 1000000],
                labels = [],
                from, to;
            
            div.innerHTML += '<b>Foreigner Tourist Density (Visits)</b><br>'; // Updated legend title

            for (var i = 0; i < grades.length; i++) {
                from = grades[i];
                to = grades[i + 1];

                labels.push(
                    '<i style="background:' + getColor(from + 1) + '"></i> ' +
                    from.toLocaleString() + (to ? '&ndash;' + to.toLocaleString() : '+')
                );
            }

            div.innerHTML += labels.join('<br>');
            return div;
        };

        legend.addTo(map);


        // ----------------------------------------------------
        // 3. Province Search Dropdown Control (Unchanged)
        // ----------------------------------------------------
        
        var searchControl = L.control({position: 'topright'});

        searchControl.onAdd = function (map) {
            var div = L.DomUtil.create('div', 'leaflet-control leaflet-search-box');
            div.innerHTML = '<select id="province-select"></select>';

            L.DomEvent.disableClickPropagation(div);
            L.DomEvent.disableScrollPropagation(div);

            return div;
        };
        
        searchControl.addTo(map);

        const selectElement = document.getElementById('province-select');
        
        const provinces = [];
        geojson_object.features.forEach(feature => {
            provinces.push(feature.properties.name);
        });
        provinces.sort(); 
        
        const bangkokIndex = provinces.indexOf('Bangkok');
        if (bangkokIndex > -1) {
            provinces.splice(bangkokIndex, 1); 
            provinces.unshift('Bangkok'); 
        }

        provinces.forEach(name => {
            const option = document.createElement('option');
            option.value = name;
            option.textContent = name;
            selectElement.appendChild(option);
        });


        /**
         * Handles dropdown selection: updates map highlight, zoom, info panel, and chart.
         */
        selectElement.onchange = function() {
            const selectedName = this.value;

            let selectedLayer = null;
            let selectedProps = null; 

            // Reset previous highlights before finding the new layer
            geojson.eachLayer(function(layer) {
                geojson.resetStyle(layer);
                if (layer.feature.properties.name === selectedName) {
                    selectedLayer = layer;
                    selectedProps = layer.feature.properties; 
                }
            });

            if (selectedLayer) {
                // Zoom to the province's bounds
                map.fitBounds(selectedLayer.getBounds());
                
                // 1. Highlight the feature
                selectedLayer.setStyle({ weight: 4, color: '#0056b3', dashArray: '', fillOpacity: 0.8 }); // Blue highlight
                if (!L.Browser.ie && !L.Browser.opera && !L.Browser.edge) { selectedLayer.bringToFront(); }

                // 2. Update info panel (to show selected info even if mouse isn't hovering)
                info.update(selectedProps);
                
                // 3. Update dynamic chart explicitly
                if (selectedProps.ForeignerAmount !== null) { 
                    updateIncomeDistributionChart(selectedProps.name, selectedProps.ForeignerAmount);
                }
            } else {
                // Fallback (shouldn't happen if options are well-defined)
                map.setView([13.736717, 100.523186], 6);
                info.update(); 
            }
        };


        // ----------------------------------------------------
        // 4. CHART.JS VISUALIZATIONS (Colors updated for blue theme)
        // ----------------------------------------------------
        document.addEventListener('DOMContentLoaded', function() {
            
            // Register the datalabels plugin globally
            Chart.register(ChartDataLabels);

            // 1. Calculate Total Amount (Visits)
            geojson_object.features.forEach(feature => {
                if (feature.properties.ForeignerAmount) {
                    totalAmount += feature.properties.ForeignerAmount;
                }
            });

            // 2. Define the dynamic chart update function
        // ✅ Make it global so other scripts can call it
        window.updateIncomeDistributionChart = function(name, amt) {
            const other = totalAmount - amt;
            document.getElementById('chartTitle').innerHTML = `Visits Distribution: <b>${name}</b> vs. Others`;

            if (incomeChartInstance) incomeChartInstance.destroy();
            const ctx = document.getElementById('incomeDistributionChart').getContext('2d');
            incomeChartInstance = new Chart(ctx, {
                type: 'doughnut',
                data: {
                    labels: [name, 'Others'],
                    datasets: [{
                        label: 'Visits',
                        data: [amt, other],
                        backgroundColor: ['#0B3D91', '#78C0E0'],
                        hoverOffset: 10
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: { position: 'bottom', labels: { font: { size: 12 } } },
                        tooltip: {
                            callbacks: {
                                label: function(c) {
                                    const v = c.parsed;
                                    const p = (v / totalAmount * 100).toFixed(2);
                                    return `${c.label}: ${v.toLocaleString()} (${p}%)`;
                                }
                            }
                        },
                        datalabels: {
                            color: '#fff',
                            font: { weight: 'bold' },
                            formatter: function(v) {
                                return ((v / totalAmount) * 100).toFixed(1) + '%';
                            }
                        }
                    }
                },
                plugins: [ChartDataLabels]
            });
        };


            window.updateIncomeDistributionChart = updateIncomeDistributionChart;
            
            // 3. Initial Chart Load (Default: Bangkok)
            const defaultProvinceName = 'Bangkok';
            const defaultProps = findProvinceData(defaultProvinceName);

            if (defaultProps) {
                updateIncomeDistributionChart(
                    defaultProps.name, 
                    defaultProps.ForeignerAmount 
                );
            }
            
            // 4. Set Dropdown Default 
            if (selectElement) {
                selectElement.value = defaultProvinceName;
            }
        });

    </script>
</body>
</html>